using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class TicketBookingService
{
    private readonly BookingDbContext _context;

    public TicketBookingService(BookingDbContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int userId, int quantity)
    {
        using var transaction = await _context.Database.BeginTransactionAsync();

        try
        {
            var eventDetails = await _context.Events
                .Where(e => e.Id == eventId)
                .SingleOrDefaultAsync();

            if (eventDetails == null || eventDetails.AvailableSeats < quantity)
            {
                return false; // Not enough available seats or event doesn't exist
            }

            eventDetails.AvailableSeats -= quantity;

            _context.Events.Update(eventDetails);
            await _context.SaveChangesAsync();

            var purchase = new TicketPurchase
            {
                EventId = eventId,
                UserId = userId,
                Quantity = quantity,
                PurchaseDate = DateTime.UtcNow
            };

            await _context.TicketPurchases.AddAsync(purchase);
            await _context.SaveChangesAsync();

            await transaction.CommitAsync();
            return true;
        }
        catch
        {
            await transaction.RollbackAsync();
            throw; // Re-throw the exception to be handled by the calling method
        }
    }
}

public class BookingDbContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<TicketPurchase> TicketPurchases { get; set; }
}

public class Event
{
    public int Id { get; set; }
    public int AvailableSeats { get; set; }
}

public class TicketPurchase
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int UserId { get; set; }
    public int Quantity { get; set; }
    public DateTime PurchaseDate { get; set; }
